class Playground {
    async run(inputs) {
        const vals = JSON.parse(inputs[0]);
        this.tree.init(vals);
        this.queue.init([]);
        this.current_level.init([]);
        this.vars.init([["level", 0], ["direction", "L -> R"]]);

        const root = this.tree.getRoot();
        if (!root) {
            this.log("Tree is empty.");
            return [];
        }

        const result = [];
        let internalQueue = [root];
        this.queue.enqueue(root.val);
        let leftToRight = true;
        let levelCounter = 0;

        this.log("Starting BFS for Zigzag Traversal");
        await this.await();

        while (internalQueue.length > 0) {
            const levelSize = internalQueue.length;
            const levelValues = [];
            this.current_level.init([]);

            this.vars.put("level", levelCounter);
            this.vars.put("direction", leftToRight ? "L -> R" : "R -> L");
            this.log(`Processing Level ${levelCounter}`);
            await this.await();

            for (let i = 0; i < levelSize; i++) {
                const node = internalQueue.shift();
                this.queue.dequeue();

                this.tree.highlight(node.id, "#00e0ff");
                this.log(`Dequeued node ${node.val}`);

                levelValues.push(node.val);
                this.current_level.push(node.val);

                if (node.left) {
                    internalQueue.push(node.left);
                    this.queue.enqueue(node.left.val);
                }
                if (node.right) {
                    internalQueue.push(node.right);
                    this.queue.enqueue(node.right.val);
                }

                await this.await();
                this.tree.highlight(node.id, null); // Reset highlight
            }

            if (!leftToRight) {
                this.log(`Direction is Right-to-Left. Reversing current level array.`);
                levelValues.reverse();
                // Visualize the reversal in the slot
                this.current_level.init([...levelValues]);
                await this.await();
            }

            result.push(levelValues);
            this.log(`Level ${levelCounter} complete. Added to result.`);

            leftToRight = !leftToRight;
            levelCounter++;
            await this.await();
        }

        this.log("Zigzag Traversal Finished.");
        return result;
    }
}
